function money(n, isRent) {
  if (n == null) return "Price upon request";
  const s = n.toLocaleString("en-US");
  return isRent ? `₱${s}/mo` : `₱${s}`;
}

// naive client-side obfuscation only — NOT real security. See note in Auth modal.
function obfuscate(str) {
  try { return btoa(unescape(encodeURIComponent(str))); } catch (e) { return str; }
}

// ---- Small building blocks ---------------------------------------------------
function TickDivider() {
  return (
    <span style={{ display: "inline-flex", alignItems: "center", margin: "0 8px", color: COLORS.line }}>
      <svg width="10" height="10" viewBox="0 0 10 10"><path d="M5 0 V10 M2 2 H8 M2 8 H8" stroke={COLORS.line} strokeWidth="1" fill="none" /></svg>
    </span>
  );
}

function Stamp({ text }) {
  const isPending = text === "Pending";
  return (
    <div style={{
      fontFamily: FONTS.mono, fontSize: 11, letterSpacing: "0.06em", textTransform: "uppercase",
      padding: "4px 9px", border: `1px solid ${isPending ? COLORS.inkSoft : COLORS.rust}`,
      color: isPending ? COLORS.inkSoft : COLORS.rust, background: COLORS.paperAlt, borderRadius: 2,
      transform: "rotate(-1.5deg)", display: "inline-block",
    }}>
      {text}
    </div>
  );
}

function SpecRow({ beds, baths, sqft, compact, unit = "sf", landOnly }) {
  const size = compact ? 13 : 14;
  if (landOnly) {
    return (
      <div style={{ display: "flex", alignItems: "center", fontFamily: FONTS.mono, fontSize: size, color: COLORS.inkSoft }}>
        <Ruler size={14} strokeWidth={1.5} style={{ marginRight: 5 }} /> {sqft.toLocaleString()} {unit} lot
      </div>
    );
  }
  return (
    <div style={{ display: "flex", alignItems: "center", fontFamily: FONTS.mono, fontSize: size, color: COLORS.inkSoft }}>
      <BedDouble size={14} strokeWidth={1.5} style={{ marginRight: 5 }} /> {beds}
      <TickDivider />
      <Bath size={14} strokeWidth={1.5} style={{ marginRight: 5 }} /> {baths}
      <TickDivider />
      <Ruler size={14} strokeWidth={1.5} style={{ marginRight: 5 }} /> {sqft.toLocaleString()} {unit}
    </div>
  );
}

function FavoriteButton({ active, onClick }) {
  return (
    <button
      onClick={(e) => { e.stopPropagation(); onClick(); }}
      aria-label={active ? "Remove from saved homes" : "Save home"}
      style={{
        position: "absolute", top: 10, right: 10, width: 32, height: 32, borderRadius: "50%",
        border: "none", background: "rgba(246,243,235,0.92)", display: "flex", alignItems: "center",
        justifyContent: "center", cursor: "pointer",
      }}
    >
      <Heart size={16} strokeWidth={1.75} color={active ? COLORS.rust : COLORS.ink} fill={active ? COLORS.rust : "none"} />
    </button>
  );
}

function ListingCard({ listing, onOpen, isFavorite, onToggleFavorite }) {
  const [hover, setHover] = useState(false);
  const isRent = listing.type === "For Rent";
  return (
    <div
      onClick={() => onOpen(listing)}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      style={{
        background: COLORS.paperAlt, border: `1px solid ${hover ? COLORS.ink : COLORS.line}`, borderRadius: 3,
        overflow: "hidden", cursor: "pointer", transition: "border-color 160ms ease, transform 160ms ease, box-shadow 160ms ease",
        transform: hover ? "translateY(-3px)" : "none",
        boxShadow: hover ? "0 14px 30px rgba(26,26,26,0.10)" : "none",
      }}
    >
      <div style={{ position: "relative", aspectRatio: "4 / 3", overflow: "hidden" }}>
        <img
          src={`https://picsum.photos/seed/${listing.seed}/640/480`}
          alt={listing.address}
          style={{ width: "100%", height: "100%", objectFit: "cover", filter: "saturate(0.9) contrast(1.02)" }}
        />
        <div style={{ position: "absolute", top: 10, left: 10 }}>
          <Stamp text={isRent ? "For rent" : "For sale"} />
        </div>
        {listing.tag && (
          <div style={{ position: "absolute", top: 10, left: 10, marginTop: 30 }}>
            <Stamp text={listing.tag} />
          </div>
        )}
        <FavoriteButton active={isFavorite} onClick={() => onToggleFavorite(listing.id)} />
      </div>
      <div style={{ padding: "16px 18px 18px" }}>
        <div style={{ fontFamily: FONTS.mono, fontSize: 20, fontWeight: 600, color: COLORS.ink }}>
          {money(listing.price, isRent)}
        </div>
        <div style={{ fontFamily: FONTS.display, fontSize: 17, color: COLORS.ink, marginTop: 4 }}>
          {listing.address}
        </div>
        <div style={{ display: "flex", alignItems: "center", fontFamily: FONTS.body, fontSize: 13, color: COLORS.inkSoft, marginBottom: 10 }}>
          <MapPin size={12} strokeWidth={1.5} style={{ marginRight: 4 }} />
          {listing.city}, {listing.state}
        </div>
        <div style={{ borderTop: `1px solid ${COLORS.line}`, paddingTop: 10 }}>
          <SpecRow beds={listing.beds} baths={listing.baths} sqft={listing.sqft} unit={listing.areaUnit} landOnly={listing.landOnly} compact />
        </div>
      </div>
    </div>
  );
}

function Detail({ listing, onClose, isFavorite, onToggleFavorite, canSave, onRequireLogin }) {
  if (!listing) return null;
  const isRent = listing.type === "For Rent";
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(26,26,26,0.55)", display: "flex", alignItems: "center", justifyContent: "center", padding: 20, zIndex: 50 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: COLORS.paperAlt, maxWidth: 780, width: "100%", maxHeight: "88vh", overflowY: "auto", border: `1px solid ${COLORS.ink}`, borderRadius: 3, position: "relative" }}>
        <button onClick={onClose} aria-label="Close" style={{ position: "absolute", top: 14, right: 14, background: COLORS.paper, border: `1px solid ${COLORS.line}`, borderRadius: "50%", width: 34, height: 34, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", zIndex: 2 }}>
          <X size={16} color={COLORS.ink} />
        </button>
        <img src={`https://picsum.photos/seed/${listing.seed}/900/560`} alt={listing.address} style={{ width: "100%", height: 320, objectFit: "cover" }} />
        <div style={{ padding: "26px 32px 32px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 10 }}>
            <div>
              <div style={{ fontFamily: FONTS.display, fontSize: 28, color: COLORS.ink }}>{listing.address}</div>
              <div style={{ display: "flex", alignItems: "center", fontFamily: FONTS.body, fontSize: 14, color: COLORS.inkSoft, marginTop: 4 }}>
                <MapPin size={13} strokeWidth={1.5} style={{ marginRight: 4 }} />
                {listing.city}, {listing.state}{listing.year ? <> &nbsp;·&nbsp; built {listing.year}</> : null}
              </div>
            </div>
            <div style={{ fontFamily: FONTS.mono, fontSize: 26, fontWeight: 600, color: COLORS.brass }}>
              {money(listing.price, isRent)}
            </div>
          </div>

          <div style={{ display: "flex", gap: 22, margin: "20px 0", padding: "14px 0", borderTop: `1px solid ${COLORS.line}`, borderBottom: `1px solid ${COLORS.line}` }}>
            <SpecRow beds={listing.beds} baths={listing.baths} sqft={listing.sqft} unit={listing.areaUnit} landOnly={listing.landOnly} />
          </div>

          <p style={{ fontFamily: FONTS.body, fontSize: 15, lineHeight: 1.65, color: COLORS.ink }}>{listing.desc}</p>

          <div style={{ display: "flex", gap: 10, marginTop: 22, flexWrap: "wrap" }}>
            <button
              style={{ fontFamily: FONTS.mono, fontSize: 13, letterSpacing: "0.04em", textTransform: "uppercase", background: COLORS.ink, color: COLORS.paperAlt, border: "none", borderRadius: 2, padding: "13px 24px", cursor: "pointer" }}
              onClick={onClose}
            >
              Schedule a tour
            </button>
            <button
              style={{ fontFamily: FONTS.mono, fontSize: 13, letterSpacing: "0.04em", textTransform: "uppercase", background: "transparent", color: isFavorite ? COLORS.rust : COLORS.ink, border: `1px solid ${isFavorite ? COLORS.rust : COLORS.line}`, borderRadius: 2, padding: "13px 20px", cursor: "pointer", display: "flex", alignItems: "center", gap: 8 }}
              onClick={() => (canSave ? onToggleFavorite(listing.id) : onRequireLogin())}
            >
              <Heart size={14} fill={isFavorite ? COLORS.rust : "none"} />
              {isFavorite ? "Saved" : "Save home"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

