// ---- Filters ---------------------------------------------------
function FilterBar({ type, setType, minBeds, setMinBeds, query, setQuery, sort, setSort, view, setView, canShowSaved, savedCount }) {
  const pill = (active) => ({
    fontFamily: FONTS.mono, fontSize: 12.5, letterSpacing: "0.02em", padding: "8px 15px", borderRadius: 999,
    cursor: "pointer", border: `1px solid ${active ? COLORS.ink : COLORS.line}`,
    background: active ? COLORS.ink : "transparent", color: active ? COLORS.paperAlt : COLORS.ink,
    transition: "all 140ms ease", whiteSpace: "nowrap",
  });
  return (
    <div>
      {canShowSaved && (
        <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
          <div style={pill(view === "browse")} onClick={() => setView("browse")}>All listings</div>
          <div style={pill(view === "saved")} onClick={() => setView("saved")}>Saved homes ({savedCount})</div>
        </div>
      )}
      <div style={{ background: COLORS.paperAlt, border: `1px solid ${COLORS.line}`, borderRadius: 4, padding: "16px 20px", display: "flex", gap: 14, alignItems: "center", flexWrap: "wrap", marginBottom: 34 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 8, color: COLORS.inkSoft, fontFamily: FONTS.mono, fontSize: 11, textTransform: "uppercase", letterSpacing: "0.08em" }}>
          <SlidersHorizontal size={13} strokeWidth={1.5} /> Filter
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {["All", "For Sale", "For Rent"].map((t) => (<div key={t} style={pill(type === t)} onClick={() => setType(t)}>{t}</div>))}
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          {[0, 2, 3, 4].map((b) => (<div key={b} style={pill(minBeds === b)} onClick={() => setMinBeds(b)}>{b === 0 ? "Any beds" : `${b}+ bed`}</div>))}
        </div>
        <div style={{ position: "relative", flex: "1 1 180px", minWidth: 160 }}>
          <Search size={14} strokeWidth={1.5} style={{ position: "absolute", left: 11, top: "50%", transform: "translateY(-50%)", color: COLORS.inkSoft }} />
          <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search barangay..." style={{ width: "100%", fontFamily: FONTS.body, fontSize: 13, padding: "9px 12px 9px 32px", border: `1px solid ${COLORS.line}`, borderRadius: 999, outline: "none", background: COLORS.paper, color: COLORS.ink, boxSizing: "border-box" }} />
        </div>
        <select value={sort} onChange={(e) => setSort(e.target.value)} style={{ fontFamily: FONTS.mono, fontSize: 12.5, padding: "9px 10px", borderRadius: 6, border: `1px solid ${COLORS.line}`, background: COLORS.paper, color: COLORS.ink, outline: "none" }}>
          <option value="newest">Newest</option>
          <option value="price-asc">Price ↑</option>
          <option value="price-desc">Price ↓</option>
        </select>
      </div>
    </div>
  );
}

// ---- Auth ---------------------------------------------------
function AuthModal({ onClose, onAuthed }) {
  const [mode, setMode] = useState("login"); // login | signup
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);

  const inputStyle = {
    width: "100%", fontFamily: FONTS.body, fontSize: 14, padding: "11px 13px",
    border: `1px solid ${COLORS.line}`, borderRadius: 4, outline: "none", background: COLORS.paper,
    color: COLORS.ink, boxSizing: "border-box", marginBottom: 12,
  };

  async function handleSubmit(e) {
    e.preventDefault();
    setError("");
    const cleanEmail = email.trim().toLowerCase();
    if (!cleanEmail || !password) { setError("Email and password are required."); return; }
    if (mode === "signup" && !name.trim()) { setError("Name is required."); return; }
    setBusy(true);
    try {
      if (mode === "signup") {
        let existing = null;
        try { existing = await window.storage.get(`user:${cleanEmail}`, true); } catch (e) { existing = null; }
        if (existing) { setError("An account with that email already exists — try logging in."); setBusy(false); return; }
        const record = { name: name.trim(), email: cleanEmail, passwordHash: obfuscate(password) };
        await window.storage.set(`user:${cleanEmail}`, JSON.stringify(record), true);
        await window.storage.set("session", JSON.stringify({ email: cleanEmail }), false);
        onAuthed(record);
      } else {
        let existing = null;
        try { existing = await window.storage.get(`user:${cleanEmail}`, true); } catch (e) { existing = null; }
        if (!existing) { setError("No account found with that email. Try signing up instead."); setBusy(false); return; }
        const record = JSON.parse(existing.value);
        if (record.passwordHash !== obfuscate(password)) { setError("Incorrect password."); setBusy(false); return; }
        await window.storage.set("session", JSON.stringify({ email: cleanEmail }), false);
        onAuthed(record);
      }
    } catch (err) {
      setError("Something went wrong — please try again.");
    }
    setBusy(false);
  }

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(26,26,26,0.55)", display: "flex", alignItems: "center", justifyContent: "center", padding: 20, zIndex: 60 }}>
      <div onClick={(e) => e.stopPropagation()} style={{ background: COLORS.paperAlt, maxWidth: 380, width: "100%", border: `1px solid ${COLORS.ink}`, borderRadius: 3, padding: "30px 28px", position: "relative" }}>
        <button onClick={onClose} aria-label="Close" style={{ position: "absolute", top: 14, right: 14, background: "transparent", border: "none", cursor: "pointer" }}>
          <X size={18} color={COLORS.ink} />
        </button>
        <div style={{ fontFamily: FONTS.display, fontSize: 24, color: COLORS.ink, marginBottom: 4 }}>
          {mode === "login" ? "Log in" : "Create an account"}
        </div>
        <div style={{ fontFamily: FONTS.body, fontSize: 13, color: COLORS.inkSoft, marginBottom: 20 }}>
          Save homes and pick up your search on any visit.
        </div>

        <form onSubmit={handleSubmit}>
          {mode === "signup" && (
            <input style={inputStyle} placeholder="Full name" value={name} onChange={(e) => setName(e.target.value)} />
          )}
          <input style={inputStyle} type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} />
          <input style={inputStyle} type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} />

          {error && (
            <div style={{ fontFamily: FONTS.mono, fontSize: 12.5, color: COLORS.rust, marginBottom: 12 }}>{error}</div>
          )}

          <button type="submit" disabled={busy} style={{ width: "100%", fontFamily: FONTS.mono, fontSize: 13, letterSpacing: "0.04em", textTransform: "uppercase", background: COLORS.ink, color: COLORS.paperAlt, border: "none", borderRadius: 2, padding: "13px 24px", cursor: busy ? "default" : "pointer", opacity: busy ? 0.6 : 1 }}>
            {busy ? "Please wait..." : mode === "login" ? "Log in" : "Sign up"}
          </button>
        </form>

        <div style={{ fontFamily: FONTS.body, fontSize: 13, color: COLORS.inkSoft, marginTop: 16, textAlign: "center" }}>
          {mode === "login" ? (
            <>New here? <span style={{ color: COLORS.brass, cursor: "pointer" }} onClick={() => { setMode("signup"); setError(""); }}>Create an account</span></>
          ) : (
            <>Already registered? <span style={{ color: COLORS.brass, cursor: "pointer" }} onClick={() => { setMode("login"); setError(""); }}>Log in</span></>
          )}
        </div>

        <div style={{ fontFamily: FONTS.mono, fontSize: 10.5, color: COLORS.inkSoft, marginTop: 18, lineHeight: 1.5, borderTop: `1px solid ${COLORS.line}`, paddingTop: 12 }}>
          Demo login — account data is stored for this app only and isn't encrypted. Don't reuse a real password here.
        </div>
      </div>
    </div>
  );
}

function AccountMenu({ user, onLogout, onViewSaved }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{ position: "relative" }}>
      <button onClick={() => setOpen((o) => !o)} style={{ display: "flex", alignItems: "center", gap: 8, background: "transparent", border: `1px solid ${COLORS.line}`, borderRadius: 999, padding: "7px 14px 7px 8px", cursor: "pointer" }}>
        <div style={{ width: 22, height: 22, borderRadius: "50%", background: COLORS.brass, color: COLORS.white, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: FONTS.mono, fontSize: 11 }}>
          {user.name.trim().charAt(0).toUpperCase()}
        </div>
        <span style={{ fontFamily: FONTS.mono, fontSize: 12.5, color: COLORS.ink }}>{user.name.split(" ")[0]}</span>
      </button>
      {open && (
        <div style={{ position: "absolute", top: "calc(100% + 8px)", right: 0, background: COLORS.paperAlt, border: `1px solid ${COLORS.line}`, borderRadius: 4, minWidth: 180, boxShadow: "0 6px 18px rgba(26,26,26,0.12)", zIndex: 10 }}>
          <div onClick={() => { onViewSaved(); setOpen(false); }} style={{ padding: "12px 16px", fontFamily: FONTS.body, fontSize: 13.5, color: COLORS.ink, cursor: "pointer", borderBottom: `1px solid ${COLORS.line}` }}>
            Saved homes
          </div>
          <div onClick={() => { onLogout(); setOpen(false); }} style={{ padding: "12px 16px", fontFamily: FONTS.body, fontSize: 13.5, color: COLORS.rust, cursor: "pointer", display: "flex", alignItems: "center", gap: 8 }}>
            <LogOut size={13} /> Log out
          </div>
        </div>
      )}
    </div>
  );
}

// ---- App ---------------------------------------------------
export default function App() {
  const [type, setType] = useState("All");
  const [minBeds, setMinBeds] = useState(0);
  const [query, setQuery] = useState("");
  const [sort, setSort] = useState("newest");
  const [active, setActive] = useState(null);
  const [view, setView] = useState("browse");

  const [user, setUser] = useState(null);
  const [authOpen, setAuthOpen] = useState(false);
  const [favorites, setFavorites] = useState([]);
  const [booting, setBooting] = useState(true);

  // restore session + favorites on load
  useEffect(() => {
    (async () => {
      try {
        const session = await window.storage.get("session", false);
        if (session) {
          const { email } = JSON.parse(session.value);
          const userRec = await window.storage.get(`user:${email}`, true);
          if (userRec) {
            setUser(JSON.parse(userRec.value));
            try {
              const favs = await window.storage.get(`favorites:${email}`, true);
              setFavorites(favs ? JSON.parse(favs.value) : []);
            } catch (e) { setFavorites([]); }
          }
        }
      } catch (e) {
        // no session yet — that's fine
      }
      setBooting(false);
    })();
  }, []);

  async function handleAuthed(record) {
    setUser(record);
    setAuthOpen(false);
    try {
      const favs = await window.storage.get(`favorites:${record.email}`, true);
      setFavorites(favs ? JSON.parse(favs.value) : []);
    } catch (e) { setFavorites([]); }
  }

  async function handleLogout() {
    try { await window.storage.delete("session", false); } catch (e) {}
    setUser(null);
    setFavorites([]);
    setView("browse");
  }

  async function toggleFavorite(id) {
    if (!user) { setAuthOpen(true); return; }
    const next = favorites.includes(id) ? favorites.filter((f) => f !== id) : [...favorites, id];
    setFavorites(next);
    try { await window.storage.set(`favorites:${user.email}`, JSON.stringify(next), true); } catch (e) {}
  }

  const filtered = useMemo(() => {
    let list = view === "saved" ? LISTINGS.filter((l) => favorites.includes(l.id)) : LISTINGS;
    list = list.filter((l) => {
      if (type !== "All" && l.type !== type) return false;
      if (minBeds > 0 && (l.landOnly || l.beds < minBeds)) return false;
      if (query && !l.city.toLowerCase().includes(query.toLowerCase()) && !l.address.toLowerCase().includes(query.toLowerCase())) return false;
      return true;
    });
    const byPrice = (a, b) => {
      if (a.price == null) return 1;
      if (b.price == null) return -1;
      return a.price - b.price;
    };
    if (sort === "price-asc") list = [...list].sort(byPrice);
    if (sort === "price-desc") list = [...list].sort((a, b) => byPrice(b, a));
    return list;
  }, [type, minBeds, query, sort, view, favorites]);

  return (
    <div style={{ background: COLORS.paper, minHeight: "100%", fontFamily: FONTS.body }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,500;9..144,600&family=Inter:wght@400;500;600&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
        * { box-sizing: border-box; }
        @media (max-width: 760px) {
          .hero-grid { grid-template-columns: 1fr !important; }
          .annotation { display: none !important; }
          .listing-grid { grid-template-columns: 1fr !important; }
          .nav-links { display: none !important; }
          .agent-banner { grid-template-columns: 1fr !important; min-height: 0 !important; }
          .agent-banner > div:first-child { min-height: 220px !important; }
        }
        @media (prefers-reduced-motion: reduce) { * { transition: none !important; } }
        button:focus-visible, input:focus-visible, select:focus-visible { outline: 2px solid ${COLORS.brass}; outline-offset: 2px; }
        .consult-btn:hover { transform: translateY(-1px); box-shadow: 0 6px 16px rgba(26,26,26,0.18); }
      `}</style>

      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 24px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "26px 0", borderBottom: `1px solid ${COLORS.line}` }}>
          <img src={LOGO_MARK} alt="GiG Realty Services" style={{ height: 34, display: "block" }} />
          <div style={{ display: "flex", gap: 20, alignItems: "center" }}>
            <span className="nav-links" style={{ fontFamily: FONTS.mono, fontSize: 13, color: COLORS.inkSoft }}>Listings</span>
            <span className="nav-links" style={{ fontFamily: FONTS.mono, fontSize: 13, color: COLORS.inkSoft }}>Agents</span>
            {!booting && (user ? (
              <AccountMenu user={user} onLogout={handleLogout} onViewSaved={() => setView("saved")} />
            ) : (
              <button onClick={() => setAuthOpen(true)} style={{ display: "flex", alignItems: "center", gap: 6, fontFamily: FONTS.mono, fontSize: 12.5, letterSpacing: "0.03em", textTransform: "uppercase", background: "transparent", color: COLORS.ink, border: `1px solid ${COLORS.line}`, borderRadius: 2, padding: "9px 16px", cursor: "pointer" }}>
                <User size={13} /> Log in
              </button>
            ))}
            <button style={{ fontFamily: FONTS.mono, fontSize: 12.5, letterSpacing: "0.03em", textTransform: "uppercase", background: COLORS.brass, color: COLORS.white, border: "none", borderRadius: 2, padding: "10px 18px", cursor: "pointer" }}>
              Inquire
            </button>
          </div>
        </div>

        <AgentBanner />

        <Hero />

        <FilterBar
          type={type} setType={setType} minBeds={minBeds} setMinBeds={setMinBeds}
          query={query} setQuery={setQuery} sort={sort} setSort={setSort}
          view={view} setView={setView} canShowSaved={!!user} savedCount={favorites.length}
        />

        {filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "60px 0", fontFamily: FONTS.mono, color: COLORS.inkSoft }}>
            {view === "saved" ? "No saved homes yet — tap the heart on any listing to save it here." : "No listings match those filters. Try widening the search."}
          </div>
        ) : (
          <div className="listing-grid" style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 22, paddingBottom: 70 }}>
            {filtered.map((l) => (
              <ListingCard key={l.id} listing={l} onOpen={setActive} isFavorite={favorites.includes(l.id)} onToggleFavorite={toggleFavorite} />
            ))}
          </div>
        )}

        <div style={{ borderTop: `1px solid ${COLORS.line}`, padding: "26px 0 40px", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 14 }}>
          <div>
            <div style={{ fontFamily: FONTS.display, fontSize: 17, fontWeight: 600, color: COLORS.ink }}>GiG Realty Services</div>
            <div style={{ fontFamily: FONTS.body, fontSize: 12, fontStyle: "italic", color: COLORS.inkSoft, marginTop: 4 }}>It's time to make your dreams come true</div>
          </div>
          <div style={{ fontFamily: FONTS.mono, fontSize: 12, color: COLORS.inkSoft }}>Tetuan · Guiwan · Putik · Pasonanca · Sta. Maria, Zamboanga City — +63 962 019 2231</div>
        </div>

        <div style={{ borderTop: `1px solid ${COLORS.line}`, padding: "20px 0 32px", fontFamily: FONTS.mono, fontSize: 11, lineHeight: 1.9, color: COLORS.inkSoft }}>
          <div style={{ fontWeight: 600, color: COLORS.ink, marginBottom: 4 }}>GIG REALTY SERVICES</div>
          <div>Yubenco Tetuan, Don Alfaro St., Tetuan, Zamboanga City</div>
          <div>Real Estate Broker — Ellah Galon</div>
          <div>REB LNo. 26849 valid until 03/28/2028</div>
          <div>PTR No. 3344852 valid until 12/31/2026</div>
          <div>DHSUD LTS No. 2321, DHSUD REB Ads Approval No. R9-AA-2025/09-006</div>
          <div>DHSUD REB COR R9-B-01/26-64 valid until 12/31/2026</div>
          <div style={{ marginTop: 6 }}>(062) 993-8268 &nbsp;·&nbsp; Viber / WhatsApp (+63) 917-623-4246</div>
        </div>
      </div>

      <Detail
        listing={active} onClose={() => setActive(null)}
        isFavorite={active ? favorites.includes(active.id) : false}
        onToggleFavorite={toggleFavorite}
        canSave={!!user}
        onRequireLogin={() => { setActive(null); setAuthOpen(true); }}
      />
      {authOpen && <AuthModal onClose={() => setAuthOpen(false)} onAuthed={handleAuthed} />}
    </div>
  );
}
